#include<bits/stdc++.h>
using namespace std;
const long long inf=(1ll<<31);
long long n,m,s;
struct edge{
	long long x,y,z;
	edge() {};
	edge(long long _x,long long _y,long long _z){
		x=_x;
		y=_y;
		z=_z;
	}
}e[500001];
long long dis[500001];
int main()
{
	cin>>n>>m>>s;
	for(int i=0;i<m;i++){
		int u,v,w;
		cin>>u>>v>>w;
		e[i].x=u;
		e[i].y=v;
		e[i].z=w;
	}
	for(int i=0;i<m;i++){
		dis[i]=inf;
	}
	dis[s]=0;
	while(1){
		int f=0;
		for(int i=0;i<m;i++){
			int x=e[i].x,y=e[i].y,w=e[i].z;
			if(dis[x]+w<dis[y]){
				dis[y]=dis[x]+w;
				f=1;
			}
		}
		if(!f)break;
	}
	for(long long i=1;i<=n;i++){
		if(dis[i]==inf)cout<<inf-1<<" ";
		else cout<<dis[i]<<" " ;
	}
}
